from typing import List

class Solution:
    def checkSubarraySum(self, nums: List[int], k: int) -> bool:
        prefix_sum = 0
        seen = {0: -1}
        for i, num in enumerate(nums):
            prefix_sum = (prefix_sum + num) % k
            if prefix_sum in seen:
                if i - seen[prefix_sum] >= 2:
                    return True
            else:
                seen[prefix_sum] = i
        return False
```
